import java.util.*;

public class ArrayListDemo {
    public static void main(String[] args) {
        ArrayList<String> list = new ArrayList<>();

        // Adding elements
        list.add("Alice");          // add to end
        list.add("Bob");
        list.add(0, "Zara");        // add at index 0 (shifts others right)

        // Accessing
        System.out.println(list.get(0));        // "Zara"
        System.out.println(list.size());        // 3
        System.out.println(list.contains("Bob")); // true
        System.out.println(list.indexOf("Alice")); // 1

        // Modifying
        list.set(1, "Ava");         // replace index 1
        list.remove("Bob");         // remove by value (first match)
        list.remove(0);             // remove by index

        // Iteration
        for (String s : list) {
            System.out.println(s);
        }

        // Sorting
        Collections.sort(list);
        System.out.println(list);   // [Ava] (only one left)

        list.clear();
        System.out.println(list.isEmpty()); // true
    }
}

import java.util.*;

public class LinkedListDemo {
    public static void main(String[] args) {
        LinkedList<Integer> ll = new LinkedList<>();

        // Deque / Queue operations
        ll.addFirst(10);    // [10]
        ll.addLast(20);     // [10, 20]
        ll.addFirst(5);     // [5, 10, 20]
        ll.addLast(30);     // [5, 10, 20, 30]

        System.out.println(ll.peekFirst()); // 5  (view without removing)
        System.out.println(ll.peekLast());  // 30
        System.out.println(ll.pollFirst()); // 5  (remove and return)
        System.out.println(ll.pollLast());  // 30 (remove and return)
        System.out.println(ll);             // [10, 20]

        // Used as a Stack (LIFO)
        LinkedList<String> stack = new LinkedList<>();
        stack.push("A");  // addFirst
        stack.push("B");  // addFirst  -> [B, A]
        System.out.println(stack.pop()); // "B" (removeFirst)
    }
}

import java.util.*;

public class HashMapDemo {
    public static void main(String[] args) {
        HashMap<String, Integer> scores = new HashMap<>();

        // Putting entries
        scores.put("Alice", 95);
        scores.put("Bob", 80);
        scores.put("Alice", 98); // overwrites previous value for "Alice"

        // Accessing
        System.out.println(scores.get("Alice"));        // 98
        System.out.println(scores.get("Eve"));          // null (key absent)
        System.out.println(scores.getOrDefault("Eve", 0)); // 0 (safe get)
        System.out.println(scores.containsKey("Bob")); // true
        System.out.println(scores.containsValue(80));  // true
        System.out.println(scores.size());              // 2

        // Iterating
        for (Map.Entry<String, Integer> entry : scores.entrySet()) {
            System.out.println(entry.getKey() + " -> " + entry.getValue());
        }

        // Frequency counting pattern (very common in exams)
        String text = "hello";
        HashMap<Character, Integer> freq = new HashMap<>();
        for (char c : text.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }
        System.out.println(freq); // {h=1, e=1, l=2, o=1}

        scores.remove("Bob");
        scores.clear();
    }
}

import java.util.*;

public class HashSetDemo {
    public static void main(String[] args) {
        HashSet<Integer> set = new HashSet<>();
        set.add(1);
        set.add(2);
        set.add(3);
        set.add(2); // duplicate — ignored silently

        System.out.println(set.size());        // 3
        System.out.println(set.contains(2));   // true
        set.remove(2);
        System.out.println(set.contains(2));   // false

        // Deduplicate a list using HashSet
        ArrayList<Integer> withDups = new ArrayList<>(Arrays.asList(1,2,2,3,3,3));
        HashSet<Integer> unique = new HashSet<>(withDups);
        System.out.println(unique.size()); // 3

        // Set operations
        HashSet<Integer> a = new HashSet<>(Arrays.asList(1, 2, 3, 4));
        HashSet<Integer> b = new HashSet<>(Arrays.asList(3, 4, 5, 6));

        // Intersection (retainAll modifies in place — use a copy)
        HashSet<Integer> intersect = new HashSet<>(a);
        intersect.retainAll(b);
        System.out.println(intersect); // [3, 4]

        // Union
        HashSet<Integer> union = new HashSet<>(a);
        union.addAll(b);
        System.out.println(union); // [1, 2, 3, 4, 5, 6]
    }
}

import java.util.*;

public class IterationDemo {
    public static void main(String[] args) {
        ArrayList<String> list = new ArrayList<>(Arrays.asList("A", "B", "C"));

        // 1. Enhanced for-loop (most common)
        for (String s : list) System.out.print(s + " "); // A B C
        System.out.println();

        // 2. Index-based for loop
        for (int i = 0; i < list.size(); i++) System.out.print(list.get(i) + " ");
        System.out.println();

        // 3. Iterator
        Iterator<String> it = list.iterator();
        while (it.hasNext()) System.out.print(it.next() + " ");
        System.out.println();

        // 4. forEach with lambda
        list.forEach(s -> System.out.print(s + " "));
        System.out.println();
    }
}

